#nullable enable // autogenerated

using System.Xml;
using MVZ2.IO;

namespace MVZ2.Metas
{
    public class AlmanacVariableOperationMultiply : AlmanacVariableOperationUnary
    {
        public AlmanacVariableOperationMultiply(AlmanacVariableReference reference) : base(reference)
        {
        }

        public override double Operate(AlmanacVariableContext context, double value)
        {
            return value * GetOperand(context);
        }
        public static AlmanacVariableOperationMultiply? FromXmlNode(XmlNode node, string defaultNsp)
        {
            var reference = XMLHelper.GetAlmanacVariableReference(node, defaultNsp);
            if (reference == null)
            {
                Log.LogError($"Cannot load variable reference of {nameof(AlmanacVariableOperationMultiply)}.");
                return null;
            }
            return new AlmanacVariableOperationMultiply(reference);
        }
    }
}
